package agent

import (
	"context"
	"fmt"
	"os"
	"path/filepath"
	"strconv"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
	gitpkg "github.com/DocumentDrivenDX/ddx/internal/git"
	"github.com/DocumentDrivenDX/ddx/internal/lockmetrics"
)

// LockRetryPolicy describes the retry/backoff curve used when attempting to
// acquire a process-shared lock that guards git index operations on the
// primary .git (the tracker-commit lock). The policy is owned by this
// package per ddx-da11a34a AC#4: callers in cli/internal/triage and
// elsewhere consult ActionRetryWithBackoff but do not duplicate the curve
// implementation here.
//
// The curve is exponential with a cap and a bounded max-retries budget so
// that lock contention is absorbed silently up to a point, after which it
// surfaces as an ordinary error to the caller. Per TD-031 §8.5
// (LockContentionContract) lock contention does NOT change persisted bead
// status; the bead remains claimable and the worker remains `draining`.
type LockRetryPolicy struct {
	// InitialBackoff is the wait before the second attempt.
	InitialBackoff time.Duration
	// MaxBackoff caps the per-step backoff after exponential growth.
	MaxBackoff time.Duration
	// Multiplier is the per-step growth factor (>= 1.0).
	Multiplier float64
	// MaxRetries bounds the number of acquisition attempts after the
	// initial try. Total attempts = MaxRetries + 1.
	MaxRetries int
	// MaxElapsed bounds the total wall-clock time spent retrying. If both
	// MaxRetries and MaxElapsed are set, the first to trip wins.
	MaxElapsed time.Duration
}

// DefaultLockRetryPolicy returns the policy used by withTrackerLock. The
// curve is intentionally tight (sub-second) for in-process tracker-commit
// contention; the larger 30s/90s/300s curve referenced by the auto-triage
// child of ddx-3c154349 lives one layer up, in cli/internal/triage —
// it consults ActionRetryWithBackoff and re-queues across drain passes,
// while this policy resolves contention within a single attempt.
func DefaultLockRetryPolicy() LockRetryPolicy {
	return LockRetryPolicy{
		InitialBackoff: 50 * time.Millisecond,
		MaxBackoff:     1 * time.Second,
		Multiplier:     2.0,
		MaxRetries:     200,
		MaxElapsed:     30 * time.Second,
	}
}

// step returns the backoff duration for retry index n (0-based: n=0 is the
// wait BEFORE the second acquisition attempt).
func (p LockRetryPolicy) step(n int) time.Duration {
	if p.InitialBackoff <= 0 {
		return 0
	}
	d := float64(p.InitialBackoff)
	m := p.Multiplier
	if m < 1 {
		m = 1
	}
	for i := 0; i < n; i++ {
		d *= m
		if p.MaxBackoff > 0 && d >= float64(p.MaxBackoff) {
			d = float64(p.MaxBackoff)
			break
		}
	}
	out := time.Duration(d)
	if p.MaxBackoff > 0 && out > p.MaxBackoff {
		out = p.MaxBackoff
	}
	return out
}

// trackerLockStaleAge is the age after which a held tracker lock is
// considered stale (owner crashed mid-commit) and may be forcibly broken.
var trackerLockStaleAge = 10 * time.Minute

// trackerLockPolicy is the active retry policy for withTrackerLock.
// Tests may swap this out via the exported helpers below.
var trackerLockPolicy = DefaultLockRetryPolicy()

// trackerLockPath returns the main-git lock directory for the given project
// root. The historical name remains because tests and older comments refer to
// the tracker lock, but the lock now protects all primary-checkout git writes:
// tracker commits, pre-dispatch checkpoint/ref updates, and landing.
//
// The lock target must be shared across linked worktrees for the same repo, so
// we prefer the primary DDx workspace when one exists instead of the caller's
// checkout-local .ddx directory.
func trackerLockPath(projectRoot string) string {
	return filepath.Join(sharedMainGitLockRoot(projectRoot), ddxroot.DirName, ".git-tracker.lock")
}

// sharedMainGitLockRoot resolves the DDx state root that should own the
// process-shared main-git lock. Linked worktrees should converge on the same
// primary workspace when one is available; otherwise we fall back to the
// normal project-scoped DDx path so convention-root projects keep their
// existing behavior.
func sharedMainGitLockRoot(projectRoot string) string {
	if workspace := gitpkg.FindNearestDDxWorkspace(projectRoot); workspace != "" {
		if info, err := os.Stat(filepath.Join(workspace, ddxroot.DirName)); err == nil && info.IsDir() {
			return workspace
		}
	}
	return ddxroot.Path(context.Background(), projectRoot)
}

// withMainGitLock acquires the process-shared main-git lock for the
// given project root, runs fn, and releases the lock. The lock is a
// directory created via os.Mkdir (atomic across processes on POSIX and
// Windows) following the same pattern as cli/internal/bead/lock.go.
//
// Contention is handled per LockRetryPolicy: exponential backoff up to a
// bounded budget. Per TD-031 §8.5 the contention itself does not change
// bead status; on budget exhaustion the caller surfaces an ordinary
// execution_failed and triage decides next steps.
func withMainGitLock(projectRoot string, fn func() error) error {
	if projectRoot == "" {
		return fn()
	}
	return withTrackerLockPolicy(projectRoot, trackerLockPolicy, fn)
}

// WithMainGitLock exposes the process-shared main-git lock to sibling
// packages that need the same serialized add/commit boundary as execute-bead
// landing and pre-dispatch checkpointing.
func WithMainGitLock(projectRoot string, fn func() error) error {
	return withMainGitLock(projectRoot, fn)
}

// withTrackerLock is retained for existing tracker/pre-dispatch call sites. It
// uses the same process-shared lock as landing so separate ddx work processes
// cannot interleave commits, ref updates, and checkout sync in the main tree.
func withTrackerLock(projectRoot string, fn func() error) error {
	return withMainGitLock(projectRoot, fn)
}

// TrackerLockSample carries timing and contention metrics for one
// withTrackerLock / withMainGitLock acquire+release cycle.
type TrackerLockSample struct {
	LockDir string
	Wait    time.Duration // time from entry to lock acquisition
	Hold    time.Duration // time the callback held the lock
	Retries int           // number of sleep-and-retry iterations (0 = acquired on first try)
}

// TrackerLockMetricsSink is called after each successful tracker-lock
// acquire+release cycle. The zero value (nil) is a no-op. Tests may swap
// this to capture metrics.
var TrackerLockMetricsSink func(TrackerLockSample)

// trackerLockContendedAttemptHook is a test-only hook fired after each
// failed acquire attempt that has been classified as real lock contention
// (a directory exists at lockDir and the stale-owner path did not reclaim
// it). It is invoked just before the retry sleep with the zero-based
// attempt index. The zero value (nil) is a no-op.
//
// Tests use this hook to deterministically synchronise with the retry
// loop — e.g. release the held lock from the hook so the next attempt
// observes a non-zero retry count without relying on time.Sleep races.
var trackerLockContendedAttemptHook func(attempt int)

// withTrackerLockPolicy is the policy-parameterised form of
// withTrackerLock; exposed at package scope so tests can pin a specific
// curve.
func withTrackerLockPolicy(projectRoot string, policy LockRetryPolicy, fn func() error) error {
	lockDir := trackerLockPath(projectRoot)
	if err := os.MkdirAll(filepath.Dir(lockDir), 0o755); err != nil {
		return fmt.Errorf("tracker lock dir: %w", err)
	}

	start := time.Now()
	retries := 0
	for attempt := 0; ; attempt++ {
		err := os.Mkdir(lockDir, 0o755)
		if err == nil {
			_ = os.WriteFile(filepath.Join(lockDir, "pid"),
				[]byte(fmt.Sprintf("%d", os.Getpid())), 0o644)
			_ = os.WriteFile(filepath.Join(lockDir, "acquired_at"),
				[]byte(time.Now().UTC().Format(time.RFC3339)), 0o644)
			break
		}

		// Classify what exists at lockDir before deciding to sleep or fail.
		// Per TD-031 §8.5: only a confirmed lock directory enters retry/backoff;
		// malformed paths are operator diagnostics, not lock contention.
		info, statErr := os.Lstat(lockDir)
		if statErr != nil {
			if os.IsNotExist(statErr) {
				// Path disappeared between Mkdir and Lstat (race). Retry immediately.
				continue
			}
			return fmt.Errorf("tracker lock stat: %w", statErr)
		}

		switch {
		case info.Mode().IsDir():
			// Real lock directory. Apply existing stale-owner policy.
			if breakStaleTrackerLock(lockDir) {
				continue
			}
			if attempt >= policy.MaxRetries {
				return lockTimeoutError(lockDir, "max retries")
			}
			if policy.MaxElapsed > 0 && time.Since(start) >= policy.MaxElapsed {
				return lockTimeoutError(lockDir, "max elapsed")
			}
			retries++
			if hook := trackerLockContendedAttemptHook; hook != nil {
				hook(attempt)
			}
			time.Sleep(policy.step(attempt))

		case info.Mode().IsRegular():
			// Malformed: lock path must be a directory, not a regular file.
			if time.Since(info.ModTime()) > trackerLockStaleAge {
				// Stale regular file: remove with single-path removal and retry immediately.
				if rmErr := os.Remove(lockDir); rmErr != nil && !os.IsNotExist(rmErr) {
					return fmt.Errorf("tracker lock: remove malformed stale file %s: %w", lockDir, rmErr)
				}
				continue
			}
			return fmt.Errorf("tracker lock: malformed lock path %s is a regular file; a lock directory was expected — remove it manually to recover", lockDir)

		default:
			// Symlink, socket, device, or other special filesystem object. Do not remove.
			return fmt.Errorf("tracker lock: malformed lock path %s has type %v; a lock directory was expected — inspect and remove it manually to recover", lockDir, info.Mode().Type())
		}
	}

	waitDur := time.Since(start)
	holdStart := time.Now()
	defer os.RemoveAll(lockDir)
	fnErr := lockmetrics.Instrument("tracker.lock", "tracker.commit", fn)
	if sink := TrackerLockMetricsSink; sink != nil {
		sink(TrackerLockSample{LockDir: lockDir, Wait: waitDur, Hold: time.Since(holdStart), Retries: retries})
	}
	return fnErr
}

func lockTimeoutError(lockDir, why string) error {
	owner := "missing"
	if pidData, perr := os.ReadFile(filepath.Join(lockDir, "pid")); perr == nil && len(pidData) > 0 {
		owner = strings.TrimSpace(string(pidData))
	}
	return fmt.Errorf("tracker lock timeout (%s, lock: %s, owner pid: %s)", why, lockDir, owner)
}

// breakStaleTrackerLock removes lockDir if its owner process is dead or the
// lock is older than trackerLockStaleAge. Returns true if the lock was broken.
func breakStaleTrackerLock(lockDir string) bool {
	pidData, err := os.ReadFile(filepath.Join(lockDir, "pid"))
	if err == nil {
		pid, err := strconv.Atoi(strings.TrimSpace(string(pidData)))
		if err == nil && pid > 0 && pid != os.Getpid() {
			if !trackerProcessAlive(pid) {
				os.RemoveAll(lockDir)
				return true
			}
		}
	}

	acquiredData, err := os.ReadFile(filepath.Join(lockDir, "acquired_at"))
	if err == nil {
		acquired, err := time.Parse(time.RFC3339, strings.TrimSpace(string(acquiredData)))
		if err == nil && time.Since(acquired) > trackerLockStaleAge {
			os.RemoveAll(lockDir)
			return true
		}

package agent

import (
	"context"
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
	"sync"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
	"github.com/stretchr/testify/require"
)

func commitTrackerForTest(projectRoot string) error {
	return withTrackerLock(projectRoot, func() error {
		return commitTrackerLocked(projectRoot)
	})
}

// initTrackerRepo creates a temp git repo with an initial commit and a
// .ddx/beads.jsonl file already committed. Returns the project root.
func initTrackerRepo(t *testing.T) string {
	t.Helper()
	root := t.TempDir()

	run := func(args ...string) {
		cmd := exec.Command("git", args...)
		cmd.Dir = root
		cmd.Env = scrubbedGitEnvInteg()
		out, err := cmd.CombinedOutput()
		if err != nil {
			t.Fatalf("git %v: %v\n%s", args, err, out)
		}
	}

	run("init", "-b", "main")
	run("config", "user.email", "test@ddx.test")
	run("config", "user.name", "DDx Test")

	require.NoError(t, os.WriteFile(filepath.Join(root, "seed.txt"), []byte("seed\n"), 0o644))
	run("add", "seed.txt")
	run("commit", "-m", "chore: initial seed")

	ddxDir := filepath.Join(root, ddxroot.DirName)
	require.NoError(t, os.MkdirAll(ddxDir, 0o755))
	require.NoError(t, os.WriteFile(filepath.Join(ddxDir, "beads.jsonl"), []byte(""), 0o644))
	run("add", ".ddx/beads.jsonl")
	run("commit", "-m", "chore: seed tracker")

	return root
}

func initConventionTrackerRepo(t *testing.T) (string, string) {
	t.Helper()

	t.Setenv("XDG_DATA_HOME", t.TempDir())

	root := t.TempDir()
	runGitInteg(t, root, "init", "-b", "main")
	runGitInteg(t, root, "config", "user.email", "test@ddx.test")
	runGitInteg(t, root, "config", "user.name", "DDx Test")
	require.NoError(t, os.WriteFile(filepath.Join(root, "seed.txt"), []byte("seed\n"), 0o644))
	runGitInteg(t, root, "add", "seed.txt")
	runGitInteg(t, root, "commit", "-m", "chore: initial seed")

	return root, ddxroot.Path(context.Background(), root)
}

// TestTrackerCommit_ConcurrentSafety verifies that two goroutines invoking
// CommitTracker against the same primary .git do not race on .git/index.lock.
// Without withTrackerLock around the git add/commit pair, one of the two
// goroutines would fail with: "fatal: Unable to create '.../.git/index.lock':
// File exists." (See bead description for the observed Phase 2 drain failure.)
func TestTrackerCommit_ConcurrentSafety(t *testing.T) {
	root := initTrackerRepo(t)
	tracker := filepath.Join(root, ddxroot.DirName, "beads.jsonl")

	const goroutines = 2
	const iterations = 8

	var wg sync.WaitGroup
	errs := make(chan error, goroutines*iterations)
	// mu guards file writes so the on-disk content is well-defined; the tested
	// race is the git-index race inside CommitTracker, not file-write ordering.
	var mu sync.Mutex
	counter := 0

	for g := 0; g < goroutines; g++ {
		wg.Add(1)
		go func(g int) {
			defer wg.Done()
			for i := 0; i < iterations; i++ {
				mu.Lock()
				counter++
				line := fmt.Sprintf(`{"id":"ddx-test-%04d-%04d","n":%d}`+"\n", g, i, counter)
				f, err := os.OpenFile(tracker, os.O_APPEND|os.O_WRONLY, 0o644)
				if err != nil {
					mu.Unlock()
					errs <- fmt.Errorf("open tracker: %w", err)
					return
				}
				_, _ = f.WriteString(line)
				_ = f.Close()
				mu.Unlock()

				if err := commitTrackerForTest(root); err != nil {
					errs <- err
					return
				}
			}
		}(g)
	}
	wg.Wait()
	close(errs)

	for err := range errs {
		if err != nil {
			if strings.Contains(err.Error(), "index.lock") {
				t.Fatalf("git index.lock contention observed (lock not effective): %v", err)
			}
			t.Fatalf("unexpected CommitTracker error: %v", err)
		}
	}

	// Sanity: the lock dir must be cleaned up after the run.
	if _, err := os.Stat(trackerLockPath(root)); !os.IsNotExist(err) {
		t.Fatalf("tracker lock dir not cleaned up: stat err = %v", err)
	}
}

func TestTrackerCommit_OnlyCommitsTrackerPath(t *testing.T) {
	root := initTrackerRepo(t)
	tracker := filepath.Join(root, ddxroot.DirName, "beads.jsonl")

	require.NoError(t, os.WriteFile(filepath.Join(root, "operator.txt"), []byte("operator staged\n"), 0o644))
	cmd := exec.Command("git", "add", "operator.txt")
	cmd.Dir = root
	cmd.Env = scrubbedGitEnvInteg()
	if out, err := cmd.CombinedOutput(); err != nil {
		t.Fatalf("git add operator.txt: %v\n%s", err, out)
	}

	require.NoError(t, os.WriteFile(tracker, []byte(`{"id":"ddx-only-tracker"}`+"\n"), 0o644))
	require.NoError(t, commitTrackerForTest(root))

	show := exec.Command("git", "show", "--name-only", "--format=", "HEAD")
	show.Dir = root
	show.Env = scrubbedGitEnvInteg()
	out, err := show.CombinedOutput()
	require.NoError(t, err, "git show HEAD: %s", out)
	names := strings.Fields(string(out))
	if len(names) != 1 || names[0] != ".ddx/beads.jsonl" {
		t.Fatalf("tracker commit touched %v, want only .ddx/beads.jsonl", names)
	}

	cached := exec.Command("git", "diff", "--cached", "--name-only")
	cached.Dir = root
	cached.Env = scrubbedGitEnvInteg()
	cachedOut, err := cached.CombinedOutput()
	require.NoError(t, err, "git diff --cached --name-only: %s", cachedOut)
	if strings.TrimSpace(string(cachedOut)) != "operator.txt" {
		t.Fatalf("pre-staged operator file was not preserved in index: %q", string(cachedOut))
	}
}

func TestCommitTrackerConventionModeCommitsXDGTracker(t *testing.T) {
	projectRoot, stateRoot := initConventionTrackerRepo(t)
	tracker := filepath.Join(stateRoot, "beads.jsonl")

	require.NoError(t, os.WriteFile(tracker, []byte(`{"id":"ddx-convention-tracker"}`+"\n"), 0o644))
	require.NoError(t, commitTrackerForTest(projectRoot))

	show := runGitInteg(t, stateRoot, "show", "--name-only", "--format=", "HEAD")
	require.Equal(t, "beads.jsonl", strings.TrimSpace(show))

	headTracker := runGitInteg(t, stateRoot, "show", "HEAD:beads.jsonl")
	require.Contains(t, headTracker, "ddx-convention-tracker")

	projectStatus := runGitInteg(t, projectRoot, "status", "--short", "--", ".ddx/beads.jsonl")
	require.Empty(t, projectStatus)
}

// TestTrackerLock_SharedAcrossLinkedWorktrees ensures the main-git lock uses a
// shared DDx workspace for linked worktrees, not the caller's checkout-local
// .ddx directory. Without this, two worktrees for the same repository can both
// enter the landing/tracker critical section and interleave ref updates.
func TestTrackerLock_SharedAcrossLinkedWorktrees(t *testing.T) {
	root := initTrackerRepo(t)
	linked := filepath.Join(t.TempDir(), "linked")
	runGitInteg(t, root, "worktree", "add", "--detach", linked)
	t.Cleanup(func() { runGitInteg(t, root, "worktree", "remove", "--force", linked) })

	require.Equal(t, trackerLockPath(root), trackerLockPath(linked), "linked worktrees must share the same main-git lock")

	acquired := make(chan string, 2)
	release := make(chan struct{})
	done := make(chan error, 2)

	go func() {
		done <- withTrackerLock(root, func() error {
			acquired <- "root"
			<-release
			return nil
		})
	}()

	select {
	case who := <-acquired:
		require.Equal(t, "root", who)
	case <-time.After(2 * time.Second):
		t.Fatal("primary worktree did not acquire the tracker lock")
	}

	go func() {
		done <- withTrackerLock(linked, func() error {
			acquired <- "linked"
			return nil
		})
	}()

	select {
	case who := <-acquired:
		t.Fatalf("linked worktree acquired the tracker lock while the primary holder was still active: %s", who)
	case <-time.After(200 * time.Millisecond):
		// Expected: the second caller is blocked on the shared lock.
	}

	close(release)

	select {
	case who := <-acquired:
		require.Equal(t, "linked", who)
	case <-time.After(2 * time.Second):
		t.Fatal("linked worktree did not acquire the tracker lock after release")
	}

	for i := 0; i < 2; i++ {
		require.NoError(t, <-done)
	}
}

// TestTrackerCommit_MalformedRegularFileLockRecovery verifies that a stale
// regular file at the lock path (as opposed to the expected directory) is
// removed with single-path removal and that CommitTracker then succeeds.
func TestTrackerCommit_MalformedRegularFileLockRecovery(t *testing.T) {
	root := initTrackerRepo(t)
	tracker := filepath.Join(root, ddxroot.DirName, "beads.jsonl")

	lockPath := trackerLockPath(root)
	require.NoError(t, os.WriteFile(lockPath, []byte("stale"), 0o644))
	// Back-date the mtime so it exceeds trackerLockStaleAge.
	staleTime := time.Now().Add(-2 * trackerLockStaleAge)
	require.NoError(t, os.Chtimes(lockPath, staleTime, staleTime))

	require.NoError(t, os.WriteFile(tracker, []byte(`{"id":"ddx-malformed-regular"}`+"\n"), 0o644))

package agent

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"path/filepath"
	"regexp"
	"strings"
	"sync"
	"time"

	agentlib "github.com/easel/fizeau"

	"github.com/DocumentDrivenDX/ddx/internal/agent/executeloop"
	agenttry "github.com/DocumentDrivenDX/ddx/internal/agent/try"
	"github.com/DocumentDrivenDX/ddx/internal/agent/work"
	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/DocumentDrivenDX/ddx/internal/escalation"
	"github.com/DocumentDrivenDX/ddx/internal/evidence"
	"github.com/DocumentDrivenDX/ddx/internal/gitlock"
	"github.com/DocumentDrivenDX/ddx/internal/workerstatus"
)

// ExecuteBeadLoopRuntime carries the non-serializable plumbing and
// per-invocation runtime intent for an execute-bead loop run. Durable knobs
// (assignee, retry caps, harness/model, powerClass bounds, etc.) live on
// config.ResolvedConfig and are passed via Run's rcfg argument.
type ExecuteBeadLoopRuntime struct {
	Log             io.Writer
	CleanupLog      io.Writer
	CleanupRunner   executionCleanupRunner
	ResourceChecker ExecutionResourceChecker
	CleanupInterval time.Duration
	CleanupTickCh   <-chan time.Time
	EventSink       io.Writer
	ProgressCh      chan<- ProgressEvent
	PreClaimHook    func(ctx context.Context) error
	// PreClaimIntakeHook runs after routing preflight and before Claim. It
	// classifies the candidate for actionability/scope; only
	// actionable_atomic proceeds directly to Claim. Non-atomic outcomes
	// skip the bead without claim. intake_error fail-opens so infrastructure
	// failures do not become hidden dispatch failures.
	PreClaimIntakeHook    PreClaimIntakeHook
	PreDispatchLintHook   func(ctx context.Context, beadID string) (LintResult, error)
	PostAttemptTriageHook func(ctx context.Context, beadID string, report ExecuteBeadReport) (TriageResult, error)
	// ProseEvidenceHook runs after a successful (landed) attempt and before
	// CloseWithEvidence so docs-changing attempts attach advisory prose-check
	// evidence to the bead's event history. Errors are logged and ignored;
	// prose findings never block closure.
	ProseEvidenceHook ProseEvidenceHook
	// PostAttemptDecompositionHook is called when a no_changes attempt signals
	// orchestrator_action: decompose in its rationale, indicating the bead is too
	// large for implementation-level splitting. The hook should run the same
	// orchestrator splitter used by the intake gate and return child specs and an
	// AC map. A nil return or error falls back to operator-required parking.
	PostAttemptDecompositionHook func(ctx context.Context, beadID string) (*PreClaimDecomposition, error)
	// ReviewCostCap, when non-nil, accumulates reviewer cost on the same
	// loop budget tracker used by the implementer attempts.
	ReviewCostCap *escalation.CostCapTracker
	// RoutePreflight, when non-nil, runs once during Run bootstrap before
	// the drain loop starts. It is expected to call upstream ResolveRoute
	// against the loop's resolved (harness, model) and return whatever typed
	// routing error the upstream surfaced — notably
	// agent.ErrHarnessModelIncompatible when the harness allow-list rejects
	// the model. Any non-nil error stops the worker before any bead is
	// claimed; DDx does NOT duplicate the upstream allow-list.
	RoutePreflight func(ctx context.Context, harness, model string) error
	// PreClaimTimeout bounds the pre-claim readiness hooks. Zero means use the
	// binary default so a hanging readiness check cannot park the worker
	// forever.
	PreClaimTimeout time.Duration
	// PreClaimWarnRepeatThreshold is the number of consecutive pre-claim warn
	// fingerprints across distinct bead IDs that trips the operator-attention
	// guard. Zero means use DefaultPreClaimWarnRepeatThreshold.
	PreClaimWarnRepeatThreshold int
	// RouteResolutionTimeout bounds the routing preflight (RoutePreflight) and
	// the resolveRoute viability check so a hung resolver cannot wedge the
	// single-threaded worker for hours while a lease is held (ddx-8f2e0ebf).
	// Zero means use DefaultRouteResolutionTimeout (60s).
	RouteResolutionTimeout time.Duration
	// ConsecutiveWedgeThreshold is the number of consecutive wedges
	// (route_resolution_timeout / progress_watchdog) on the same bead that
	// trips the consecutive-wedge guard: the worker stops re-claiming the bead
	// and parks it for operator attention. Zero means use
	// DefaultConsecutiveWedgeThreshold (2) (ddx-9714eaac).
	ConsecutiveWedgeThreshold int
	// ClaimSuccessRateWindow and ClaimSuccessRateThreshold control the rolling
	// claim-throughput warning emitted by ddx work. A full window whose claim
	// success rate is at or below the configured threshold triggers a single
	// operator-visible warning until a later successful claim clears the warned
	// state.
	ClaimSuccessRateWindow    int
	ClaimSuccessRateThreshold float64
	// BudgetStop, when non-nil, is checked before selecting the next bead. It
	// lets CLI/server callers surface already-tripped budget state as a typed
	// work-layer StopCondition before any new bead is claimed. The companion
	// report is still appended for operator visibility, but the stop itself is
	// classified through work.StopConditionBudget.
	BudgetStop func() (work.StopDecision, ExecuteBeadReport, bool)
	// BinaryRefreshCheck, when non-nil, is checked before selecting the next
	// bead. A true result means the caller has started a replacement worker
	// with equivalent arguments and this loop should exit before claiming work.
	// Errors are logged and fail open so update-probing never blocks the queue.
	BinaryRefreshCheck func(ctx context.Context) (bool, error)
	// Mode and IdleInterval are the runtime loop intent. Once and
	// PollInterval remain for older tests/callers but production entry points
	// should set Mode and IdleInterval directly.
	Mode         executeloop.Mode
	IdleInterval time.Duration
	Once         bool
	PollInterval time.Duration
	NoReview     bool
	// PostMergeReview enables the legacy post-land/pre-close review state
	// machine for callers that explicitly opt into that manual flow. The
	// default production close path remains owned by candidate-cycle review.
	PostMergeReview        bool
	LabelFilter            string
	IgnoreCooldown         bool
	CooldownOverrideReason string
	SessionID              string
	WorkerID               string
	ProjectRoot            string
	// TargetBeadID, when non-empty, restricts nextCandidate to only return the
	// named bead from the execution-ready queue. Used by `ddx try <bead-id>`
	// to dispatch a single specific bead through the same claim → executor →
	// land path the queue drain uses. When empty, the picker behaves normally.
	TargetBeadID string
	// WakeCh, when non-nil, signals the idle-poll sleep to return immediately
	// so the loop re-scans the queue. Used by the operator-prompt approve /
	// auto-approve mutations (Story 15) to avoid an idle-interval-sized delay
	// before a freshly-approved bead is claimed. Implementations must send
	// non-blocking (server-side helpers do); the loop only waits for a
	// receive on WakeCh during the idle sleep, never elsewhere.
	WakeCh <-chan struct{}

	// FinalizeDurableAudit, when non-nil, is called once per finalized attempt
	// after the loop has finished writing the attempt's durable tracker state.
	// Errors are terminal for autonomous work: the worker stops so DDx-managed
	// audit outputs are not left dirty while more beads are claimed.
	FinalizeDurableAudit func(report ExecuteBeadReport) error
	// PostLadderExhaustionHook, when non-nil, is called when a bead's
	// consecutive_ladder_exhaustions counter reaches the auto-recovery
	// threshold (>= 2). A nil hook or Attempted=false result falls through to
	// the existing loop path unchanged.
	PostLadderExhaustionHook PostLadderExhaustionHook
}

func (r ExecuteBeadLoopRuntime) loopIntent() (executeloop.Mode, time.Duration) {
	mode := r.Mode
	if mode == "" {
		if r.Once {
			mode = executeloop.ModeOnce
		} else {
			mode = executeloop.ModeDrain
		}
	}
	idleInterval := r.IdleInterval
	if idleInterval == 0 && mode == executeloop.ModeWatch {
		idleInterval = r.PollInterval
	}
	if idleInterval == 0 && mode == executeloop.ModeWatch {
		idleInterval = 30 * time.Second
	}
	return mode, idleInterval
}

// DefaultRouteResolutionTimeout bounds routing preflight and the resolveRoute
// viability check when ExecuteBeadLoopRuntime.RouteResolutionTimeout is unset.
// A hung resolver previously wedged the single-threaded worker for hours while
// holding a lease (ddx-8f2e0ebf); 60s is short enough to release promptly and
// long enough not to false-trip a slow-but-healthy resolver.
const DefaultRouteResolutionTimeout = 60 * time.Second

// effectiveRouteResolutionTimeout returns the configured route-resolution
// timeout, falling back to DefaultRouteResolutionTimeout when unset.
func (r ExecuteBeadLoopRuntime) effectiveRouteResolutionTimeout() time.Duration {
	if r.RouteResolutionTimeout > 0 {
		return r.RouteResolutionTimeout
	}
	return DefaultRouteResolutionTimeout
}

// DefaultConsecutiveWedgeThreshold is the number of consecutive wedges on the
// same bead that trips the consecutive-wedge guard when
// ExecuteBeadLoopRuntime.ConsecutiveWedgeThreshold is unset. A single transient
// wedge (count 1) stays below the default so the bead remains re-claimable; two
// consecutive wedges sideline it for operator attention (ddx-9714eaac).
const DefaultConsecutiveWedgeThreshold = 2

// effectiveConsecutiveWedgeThreshold returns the configured consecutive-wedge
// threshold, falling back to DefaultConsecutiveWedgeThreshold when unset.
func (r ExecuteBeadLoopRuntime) effectiveConsecutiveWedgeThreshold() int {
	if r.ConsecutiveWedgeThreshold > 0 {
		return r.ConsecutiveWedgeThreshold
	}
	return DefaultConsecutiveWedgeThreshold
}

// DefaultClaimSuccessRateWindow is the number of recent claim attempts used to
// compute the rolling claim-success rate warning.
const DefaultClaimSuccessRateWindow = 10

// effectiveClaimSuccessRateWindow returns the configured claim-success window,
// falling back to DefaultClaimSuccessRateWindow when unset.
func (r ExecuteBeadLoopRuntime) effectiveClaimSuccessRateWindow() int {
	if r.ClaimSuccessRateWindow > 0 {
		return r.ClaimSuccessRateWindow
	}
	return DefaultClaimSuccessRateWindow
}

// DefaultClaimSuccessRateThreshold is the minimum rolling claim-success rate
// before the loop emits a warning. Zero means only a full window of
// non-successes trips the signal.
const DefaultClaimSuccessRateThreshold = 0.0

// effectiveClaimSuccessRateThreshold returns the configured claim-success
// threshold, falling back to DefaultClaimSuccessRateThreshold when unset.
func (r ExecuteBeadLoopRuntime) effectiveClaimSuccessRateThreshold() float64 {
	if r.ClaimSuccessRateThreshold >= 0 {
		return r.ClaimSuccessRateThreshold
	}
	return DefaultClaimSuccessRateThreshold
}

// DefaultPreClaimWarnRepeatThreshold is the number of consecutive identical
// pre-claim warn fingerprints across distinct bead IDs required to trip the
// operator-attention guard.
const DefaultPreClaimWarnRepeatThreshold = 5

// effectivePreClaimWarnRepeatThreshold returns the configured pre-claim warn
// repeat threshold, falling back to DefaultPreClaimWarnRepeatThreshold when
// unset.
func (r ExecuteBeadLoopRuntime) effectivePreClaimWarnRepeatThreshold() int {
	if r.PreClaimWarnRepeatThreshold > 0 {
		return r.PreClaimWarnRepeatThreshold
	}
