	".ddx/beads.jsonl",
	".ddx/beads-archive.jsonl",
	".ddx/metrics/attempts.jsonl",
	".ddx/attachments",
}

type durableAuditBeadReader interface {
	Get(args ...any) (*bead.Bead, error)
}

// FinalizeDurableAttemptAudit appends the per-attempt metrics row, when the
// report carries an attempt_id, and commits any DDx-managed durable audit files
// that changed during the attempt.
func FinalizeDurableAttemptAudit(projectRoot string, store durableAuditBeadReader, report ExecuteBeadReport) error {
	if strings.TrimSpace(projectRoot) == "" {
		projectRoot = report.ProjectRoot
	}
	if strings.TrimSpace(projectRoot) == "" {
		return fmt.Errorf("finalize durable audit: project root required")
	}
	if strings.TrimSpace(report.AttemptID) != "" {
		if err := attemptmetrics.AppendRow(projectRoot, buildAttemptMetricsRow(store, report, time.Now().UTC())); err != nil {
			return fmt.Errorf("append attempt metrics: %w", err)
		}
	}
	if err := CommitDurableAuditOutputs(projectRoot, report.AttemptID); err != nil {
		return fmt.Errorf("commit durable audit outputs: %w", err)
	}
	return nil
}

// CommitDurableAuditOutputs stages and commits the DDx-managed durable audit
// paths when they are dirty. The commit is serialized through the main git lock
// so concurrent workers cannot interleave tracker and audit commits.
func CommitDurableAuditOutputs(projectRoot, attemptID string) error {
	return withTrackerLock(projectRoot, func() error {
		return commitDurableAuditOutputsLocked(projectRoot, attemptID)
	})
}

func buildAttemptMetricsRow(store durableAuditBeadReader, report ExecuteBeadReport, finishedAt time.Time) attemptmetrics.AttemptRow {
	specID := ""
	if report.BeadID != "" && store != nil {
		if b, err := store.Get(context.Background(), report.BeadID); err == nil && b != nil {
			specID, _ = b.Extra["spec-id"].(string)
		}
	}
	tsEnd := attemptmetrics.Rfc3339(finishedAt)
	tsStart := ""
	if report.DurationMS > 0 {
		start := finishedAt.Add(-time.Duration(report.DurationMS) * time.Millisecond)
		tsStart = attemptmetrics.Rfc3339(start)
	}
	return attemptmetrics.AttemptRow{
		SchemaVersion: attemptmetrics.SchemaVersion,
		AttemptID:     report.AttemptID,
		BeadID:        report.BeadID,
		SessionID:     report.SessionID,
		TSStart:       tsStart,
		TSEnd:         tsEnd,
		Model:         report.Model,
		Harness:       report.Harness,
		Profile:       report.RequestedProfile,
		Provider:      report.Provider,
		SpecID:        specID,
		Outcome:       report.Status,
		CostUSD:       report.CostUSD,
		DurationMS:    int(report.DurationMS),
		ReviewVerdict: report.ReviewVerdict,
	}
}

func commitDurableAuditOutputsLocked(projectRoot, attemptID string) error {
	ctx, cancel := context.WithTimeout(context.Background(), 30*time.Second)
	defer cancel()

		return nil, nil, fmt.Errorf("rechecking pre-dispatch dirt: %w", err)
	}
	return intersectPreDispatchDirtyPaths(currentPaths, normalized), currentPaths, nil
}

func resolveOptionalGitRef(dir, ref string) (string, bool) {
	out, err := internalgit.Command(context.Background(), dir, "rev-parse", "-q", "--verify", ref).Output()
	if err != nil {
		return "", false
	}
	sha := strings.TrimSpace(string(out))
	if sha == "" {
		return "", false
	}
	return sha, true
}

func preDispatchDirtyRecoverCommand(preserveRef string) string {
	if preserveRef == "" {
		return ""
	}
	return "git stash apply " + preserveRef
}

func preservePreDispatchDirtyPaths(projectRoot string, dirtyPaths []string) (*PreDispatchDirtyPreservation, error) {
	if projectRoot == "" {
		return nil, fmt.Errorf("project root is required for pre-dispatch dirty preservation")
	}
	normalized := normalizePreDispatchDirtyPaths(dirtyPaths)
	if len(normalized) == 0 {
		return nil, fmt.Errorf("no dirty implementation paths to preserve")
	}

	var preserved *PreDispatchDirtyPreservation
	if err := withTrackerLock(projectRoot, func() error {
		var err error
		preserved, err = preservePreDispatchDirtyPathsLocked(projectRoot, normalized)
		return err
	}); err != nil {
		return nil, err
	}
	return preserved, nil
}

func preservePreDispatchDirtyPathsLocked(projectRoot string, dirtyPaths []string) (*PreDispatchDirtyPreservation, error) {
	if err := internalgit.Command(context.Background(), projectRoot, "rev-parse", "--is-inside-work-tree").Run(); err != nil {
		return nil, fmt.Errorf("verifying project worktree for pre-dispatch preservation: %w", err)
	}
	if out, err := internalgit.Command(context.Background(), projectRoot, "rev-parse", "--verify", "HEAD").CombinedOutput(); err != nil {
		return nil, fmt.Errorf("resolving HEAD for pre-dispatch preservation: %s: %w", strings.TrimSpace(string(out)), err)
	}

	stashBefore, _ := resolveOptionalGitRef(projectRoot, "refs/stash")
	preserveID := GenerateAttemptID()
	preserveRef := preDispatchDirtyPreserveRefPrefix + preserveID
	stashMsg := "ddx pre-dispatch preserve " + preserveID
				Outcome:           ExecuteBeadOutcomeTaskFailed,
				Status:            ExecuteBeadStatusResourceExhausted,
				ProjectRoot:       projectRoot,
				ResourceExhausted: &resourceErr.Result,
			}
			res.FailureMode = ClassifyFailureMode(res.Outcome, res.ExitCode, res.Error)
			return res, nil
		}
		return nil, err
	}

	attemptID := GenerateAttemptID()

	// Serialize the parent-repo mutating pre-dispatch sequence (tracker
	// commit, caller-dirt checkpoint, base resolution, workspace creation)
	// under the tracker lock. Without this, concurrent workers race on the
	// parent's HEAD ref between unlocked CommitTracker and SynthesizeCommit
	// and surface as "cannot lock ref 'HEAD': is at X but expected Y" CAS
	// failures (regression: concurrent `ddx work` against the same project).
	// The lock is held only across the brief pre-dispatch sequence (~1-2s);
	// agent execution that follows is fully parallel.
	var baseRev string
	var workspace *AttemptWorkspace
	if err := withTrackerLock(projectRoot, func() error {
		// Commit beads.jsonl before spawning the attempt workspace so its snapshot
		// includes any bead metadata updates (e.g. spec-id).
		if err := commitTrackerLocked(projectRoot); err != nil {
			return err
		}
		// Checkpoint any remaining caller dirt as a real commit on the current
		// branch (FEAT-012 §22, US-126 AC#1). Use a temp-index commit-tree path
		// here so parent checkout hooks and runtime artifacts cannot fail the
		// dispatch before the isolated worker worktree exists.
		if _, err := checkpointPreDispatchDirt(projectRoot, attemptID); err != nil {
			return fmt.Errorf("pre-execute-bead checkpoint: %w", err)
		}
		// Resolve base revision after the tracker + checkpoint commits.
		rev, err := resolveBase(gitOps, projectRoot, runtime.FromRev)
		if err != nil {
			return err
		}

		return nil, fmt.Errorf("listing changed files: %s: %w", strings.TrimSpace(string(out)), err)
	}
	var paths []string
	for _, line := range strings.Split(strings.TrimSpace(string(out)), "\n") {
		if p := strings.TrimSpace(line); p != "" {
			paths = append(paths, p)
		}
	}
	return paths, nil
}

// FetchOriginAncestryCheck performs an origin ancestry check that first fetches
// origin/<targetBranch>. Because it performs network I/O it MUST NOT be called
// from the network-free `ddx work` drain loop (reliability principle P9,
// docs/helix/06-iterate/reliability-principles.md). The drain-loop and `ddx try`
// pre-claim hooks call LocalAncestryCheck instead; this fetch variant is
// reserved for the operator-driven refresh path (FEAT-023 `ddx sync`).
func (RealLandingGitOps) FetchOriginAncestryCheck(dir, targetBranch string) (PreClaimResult, error) {
	var result PreClaimResult
	err := withMainGitLock(dir, func() error {
		var checkErr error
		result, checkErr = fetchOriginAncestryCheckLocked(dir, targetBranch)
		return checkErr
	})
	return result, err
}

// LocalAncestryCheck compares the local target branch against the last-observed
// origin remote-tracking ref (refs/remotes/origin/<targetBranch>) WITHOUT any
// network I/O. It is the network-free pre-claim check used by the `ddx work`
// drain loop and `ddx try` (reliability principle P9: `git fetch` is never
// called from the queue loop). Refreshing the remote-tracking ref is the
// operator's responsibility via FEAT-023 `ddx sync`. When no origin remote is
// configured, or no remote-tracking ref has been observed yet, the check
